/**
 * Meshy API firewall config generator.
 *
 * Data source: https://docs.meshy.ai/en/api/authentication
 *
 * Meshy uses Bearer API key authentication.
 * API key examples use an msy_ prefix.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.meshy.ai/en/api/authentication";
const PLACEHOLDER_VALUE = "msy_CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Meshy API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:meshy",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const meshyFirewall = {",
    '  name: "meshy",',
    '  description: "Meshy API",',
    "  placeholders: {",
    `    MESHY_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.meshy.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.MESHY_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Meshy firewall config...");
  const ts = generateTypeScript();
  writeOutput("meshy", ts, import.meta.dirname);
}
